<Stats id="monster-cerynitis--stats" atts={[18,31,16,11,20,19]} bab={9} cmb={14} cmd={39} cmdP="43 vs. trip" feats={["Dodge","Improved Initiative","Lightning Stance","Mobility","Run","Wind Stance"]} skills={{"acro":{"b":16,"x":"+76 when jumping"},"ea":{"b":21},"k":{"r":5},"per":{"b":17}}} racial="+60 Acrobatics when jumping, +10 Escape Artist, +4 Knowledge (religion)" lang={["S",";",[<em>speak with animals</em>]]} />
