<Stats id="monster-charau_ka_devotee_of_the_ravener_king--stats" atts={[13,15,16,8,16,16]} bab={5} cmb={5} cmd={18} feats={["Combat Casting","Improved Natural Armor","Point-Blank Shot","Selective Channeling",["Throw Anything",<sup>B</sup>]]} skills={{"climb":{"b":11},"k":{"r":4},"per":{"b":4},"spc":{"b":6},"stl":{"b":8}}} racial="+4 Stealth" lang={["A","Po"]} combat={[["Scure moderate wounds"],["2","Sinvisibility"]]} othergear={[["+1","Ah"],["+1","Wsp"],["Rprot1"],<>ivory <Link to="/eq-misc/holy_symbol_wooden">holy symbol</Link> worth 30 gp</>,["Qmwk manacles"]]} />
