<Stats id="monster-coryphae--stats" atts={[15,21,16,10,12,21]} bab={5} cmb={10} cmd={23} feats={["Agile Maneuvers","Dodge","Improved Initiative","Mobility",["Quicken Spell-Like Ability"," (ghost sound)"]]} skills={{"acro":{"b":18},"ea":{"b":18},"per":{"b":14},"perf":{"of":"dance","b":18},"stl":{"b":18}}} lang={["Ak","U"]} />
